"""matplotlib.dates — date handling for matplotlib."""

import numpy as _np
from matplotlib.ticker import Locator, Formatter

# Epoch: days since 0001-01-01 UTC + 1 (matplotlib convention)
EPOCH_OFFSET = 719163  # days from 0001-01-01 to 1970-01-01

MICROSECONDLY = 0
SECONDLY = 1
MINUTELY = 2
HOURLY = 3
DAILY = 4
WEEKLY = 5
MONTHLY = 6
YEARLY = 7

MO, TU, WE, TH, FR, SA, SU = range(7)


def date2num(d):
    """Convert datetime to matplotlib float date."""
    if hasattr(d, '__iter__'):
        return _np.array([date2num(di) for di in d])
    if hasattr(d, 'timestamp'):
        return d.timestamp() / 86400.0 + EPOCH_OFFSET
    return float(d)


def num2date(x, tz=None):
    """Convert matplotlib float date to datetime."""
    import datetime
    if hasattr(x, '__iter__'):
        return [num2date(xi, tz) for xi in x]
    days = float(x) - EPOCH_OFFSET
    return datetime.datetime(1970, 1, 1) + datetime.timedelta(days=days)


def datestr2num(d, default=None):
    """Convert date string to number."""
    import datetime
    try:
        dt = datetime.datetime.fromisoformat(str(d))
        return date2num(dt)
    except (ValueError, TypeError):
        return 0.0


def num2timedelta(x):
    import datetime
    return datetime.timedelta(days=x)


def drange(dstart, dend, delta):
    """Return a sequence of equally spaced dates."""
    f1 = date2num(dstart)
    f2 = date2num(dend)
    step = delta.total_seconds() / 86400.0
    return _np.arange(f1, f2, step)


def epoch2num(e):
    return _np.asarray(e) / 86400.0 + EPOCH_OFFSET


def num2epoch(d):
    return (d - EPOCH_OFFSET) * 86400.0


def set_epoch(epoch):
    pass


def get_epoch():
    return '1970-01-01T00:00:00'


# ── Locators ────────────────────────────────────────────────────

class DateLocator(Locator):
    def __init__(self, tz=None):
        self.tz = tz


class AutoDateLocator(DateLocator):
    def __init__(self, tz=None, minticks=5, maxticks=None, interval_multiples=True):
        super().__init__(tz)
        self.minticks = minticks
        self.maxticks = maxticks


class YearLocator(DateLocator):
    def __init__(self, base=1, month=1, day=1, tz=None):
        super().__init__(tz)
        self.base = base


class MonthLocator(DateLocator):
    def __init__(self, bymonth=None, bymonthday=1, interval=1, tz=None):
        super().__init__(tz)
        self.bymonth = bymonth
        self.interval = interval


class WeekdayLocator(DateLocator):
    def __init__(self, byweekday=0, interval=1, tz=None):
        super().__init__(tz)


class DayLocator(DateLocator):
    def __init__(self, bymonthday=None, interval=1, tz=None):
        super().__init__(tz)
        self.interval = interval


class HourLocator(DateLocator):
    def __init__(self, byhour=None, interval=1, tz=None):
        super().__init__(tz)


class MinuteLocator(DateLocator):
    def __init__(self, byminute=None, interval=1, tz=None):
        super().__init__(tz)


class SecondLocator(DateLocator):
    def __init__(self, bysecond=None, interval=1, tz=None):
        super().__init__(tz)


class MicrosecondLocator(DateLocator):
    pass


class RRuleLocator(DateLocator):
    def __init__(self, o, tz=None):
        super().__init__(tz)


# ── Formatters ──────────────────────────────────────────────────

class DateFormatter(Formatter):
    def __init__(self, fmt, tz=None, *, usetex=None):
        self.fmt = fmt
        self.tz = tz

    def __call__(self, x, pos=None):
        try:
            dt = num2date(x)
            return dt.strftime(self.fmt)
        except Exception:
            return str(x)


class AutoDateFormatter(Formatter):
    def __init__(self, locator, tz=None, defaultfmt='%Y-%m-%d'):
        self.locator = locator
        self.defaultfmt = defaultfmt

    def __call__(self, x, pos=None):
        try:
            dt = num2date(x)
            return dt.strftime(self.defaultfmt)
        except Exception:
            return str(x)


class ConciseDateFormatter(AutoDateFormatter):
    def __init__(self, locator, tz=None, formats=None, zero_formats=None,
                 offset_formats=None, show_offset=True, *, usetex=None):
        super().__init__(locator, tz)


